using System.Web.Mvc;
using System.Linq;
using System.Data.Entity;

public class ReviewsController : Controller
{
    private readonly ApplicationDbContext _context;

    public ReviewsController()
    {
        _context = new ApplicationDbContext();
    }

    // GET: Reviews/ProductReviews/5
    public ActionResult ProductReviews(int productId)
    {
        var reviews = _context.Reviews
                              .Where(r => r.ProductId == productId)
                              .ToList();
        return View(reviews);
    }
}

// Razor View: ProductReviews.cshtml

@model IEnumerable<YourNamespace.Models.Review>

<div>
    <h2>Product Reviews</h2>
    @foreach (var review in Model)
    {
        <div class="review">
            <h4>@review.Title</h4>
            <p>@Html.Raw(review.Content)</p>
            <p><em>By @review.AuthorName on @review.DateSubmitted.ToString("MM/dd/yyyy")</em></p>
        </div>
    }
</div>

// Database Context and Review Model for reference:

public class ApplicationDbContext : DbContext
{
    public DbSet<Review> Reviews { get; set; }
}

public class Review
{
    public int Id { get; set; }
    public int ProductId { get; set; }
    public string Title { get; set; }
    public string Content { get; set; }
    public string AuthorName { get; set; }
    public DateTime DateSubmitted { get; set; }
}